-- todo 20250712 deveria chamar tenant_etype
DROP TABLE etype CASCADE CONSTRAINTS;
CREATE TABLE etype (
    id             NUMBER GENERATED BY DEFAULT ON NULL AS IDENTITY PRIMARY KEY,
    tenant_code    VARCHAR2(50)        NOT NULL,
    --
    hash           INT GENERATED ALWAYS AS (ORA_HASH(code)) VIRTUAL,
    code           VARCHAR2(20),
    id_perfil_old  INTEGER,
    tag_perfil_old VARCHAR2(30),
    name           VARCHAR2(50)        NOT NULL,
    plural_name    VARCHAR2(50)        NOT NULL,
    description    VARCHAR2(200),
    read_only      NUMBER(1) DEFAULT 1 NOT NULL,
    is_admin       NUMBER(1) DEFAULT 1 NOT NULL,
    active         NUMBER(1) DEFAULT 1 NOT NULL,
    --
    CONSTRAINT uk_etype_tenant_code UNIQUE (tenant_code, code)
);



